arguments.command:
cd astrohub && python -c "
import sys, io
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')
# Find the API route for speed
lines = open('src/main/main.py', 'r', encoding='utf-8').readlines()
for i, line in enumerate(lines, 1):
    if 'speed/run' in line.lower() or 'speed_test' in line.lower() or 'run_speed' in line.lower():
        start = max(0, i-5)
        end = min(len(lines), i+30)
        for j in range(start, end):
            print(f'L{j}: {lines[j-1].rstrip()[:150]}')
        print('---')" 2>&1

cd astrohub && python -c "
import sys, io, os
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')
# Search all Python files for speed route
for root, dirs, files in os.walk('src'):
    for f in files:
        if f.endswith('.py'):
            path = os.path.join(root, f)
            try:
                lines = open(path, 'r', encoding='utf-8').readlines()
                for i, line in enumerate(lines, 1):
                    if 'speed' in line.lower() and ('/api' in line.lower() or 'route' in line.lower() or 'advanced' in line.lower()):
                        print(f'{path}:{i}: {line.rstrip()[:150]}')
            except:
                pass" 2>&1

content.text:
        function renderSpeedResults(results) {
            var area = document.getElementById('speedResultArea');
            if (!results || Object.keys(results).length === 0) {
                area.innerHTML = '<div class="advanced-status-panel"><p style="color:#6e7681">暂无结果</p></div>';
                return;
            }
            var html = '<div class="advanced-status-panel"><h4>速度测试结果</h4>';
            // Speed mapping table
            var speedMap = results.speed_map || results.speed_mapping || {};
            var mapKeys = Object.keys(speedMap);
            if (mapKeys.length > 0) {
                html += '<table class="result-table" style="margin:12px 0"><thead><tr><th>速度档位</th><th>实际速率 (°/s)</th></tr></thead><tbody>';
                mapKeys.forEach(function(k) {
                    html += '<tr><td>' + k + '</td><td>' + speedMap[k] + '</td></tr>';
                });
                html += '</tbody></table>';
            }
