        // v7.15: 加载本机信息
        function loadLocalhostInfo() {
            apiGet('/api/v1/localhost').then(function(result) {
                if (result.success && result.data) {
                    var info = result.data;
                    document.getElementById('localhost-hostname').textContent = info.hostname || '-';
                    document.getElementById('localhost-cpu').textContent = info.cpu_model || '-';
                    document.getElementById('localhost-ram').textContent = info.ram_gb ? info.ram_gb + ' GB' : '-';
                    var gpu = (info.gpu_names || []).join(', ') || '-';
                    if (info.vram_gb > 0) gpu += ' (' + info.vram_gb + 'GB)';
                    document.getElementById('localhost-gpu').textContent = gpu;
                    document.getElementById('localhost-ip').textContent = info.local_ip || '-';
                    document.getElementById('localhost-gateway').textContent = info.gateway || '-';
                    window.localhostGateway = info.gateway; // 保存网关供后续使用
                    document.getElementById('localhostCard').style.display = 'block';
                    
                    // v7.15: 首次运行，显示提示并重启
                    if (result.first_run) {
                        showStartupProgress();
                    }
                }
            }).catch(function(e) { console.warn('加载本机信息失败:', e); });
        }
        // v7.15: 显示启动进度条
        
        // v7.15: 网页级别弹窗
        window.showAlert = function(message, title) {
            var alertHtml = '<div id="alertModal" class="modal-overlay" onclick="closeAlert()" style="position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;z-index:10000">' +
                '<div onclick="event.stopPropagation()" style="background:#1a1e2e;padding:24px;border-radius:12px;min-width:300px;max-width:500px;box-shadow:0 4px 20px rgba(0,0,0,0.5)">' +
                '<h3 style="margin:0 0 16px 0;color:#f0883e">' + (title || '提示') + '</h3>' +
                '<p style="margin:0 0 20px 0;color:#e0e6f0;line-height:1.6">' + message + '</p>' +
                '<button class="btn btn-primary" onclick="closeAlert()" style="width:100%">确定</button></div></div>';
            document.body.insertAdjacentHTML('beforeend', alertHtml);
        };
        window.closeAlert = function() {
            var modal = document.getElementById('alertModal');
            if (modal) modal.remove();
        };
        window.showConfirm = function(message, onConfirm, title) {
            var confirmHtml = '<div id="confirmModal" class="modal-overlay" style="position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;z-index:10000">' +
                '<div onclick="event.stopPropagation()" style="background:#1a1e2e;padding:24px;border-radius:12px;min-width:300px;max-width:500px;box-shadow:0 4px 20px rgba(0,0,0,0.5)">' +
                '<h3 style="margin:0 0 16px 0;color:#58a6ff">' + (title || '确认') + '</h3>' +
                '<p style="margin:0 0 20px 0;color:#e0e6f0;line-height:1.6">' + message + '</p>' +
                '<div style="display:flex;gap:12px;justify-content:flex-end">' +
                '<button class="btn btn-secondary" onclick="closeConfirm(false)">取消</button>' +
                '<button class="btn btn-primary" onclick="closeConfirm(true)">确定</button></div></div></div>';
            window._confirmCallback = onConfirm;
            document.body.insertAdjacentHTML('beforeend', confirmHtml);
        };
        window.closeConfirm = function(result) {
            var modal = document.getElementById('confirmModal');
            if (modal) modal.remove();
            if (result && window._confirmCallback) {
                window._confirmCallback();
                window._confirmCallback = null;
            }
        };
        
function showStartupProgress() {
            var progressHtml = '<div id="startupOverlay" style="position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.9);display:flex;flex-direction:column;align-items:center;justify-content:center;z-index:99999">' +
                '<div style="text-align:center;color:#e0e6f0">' +
                '<div style="font-size:24px;margin-bottom:20px">🚀 首次运行，正在收集本机信息...</div>' +
                '<div class="progress-bar" style="width:300px;height:6px;background:#30363d;border-radius:3px;overflow:hidden">' +
                '<div id="startupProgress" style="width:0%;height:100%;background:linear-gradient(90deg,#58a6ff,#3fb950);transition:width 0.3s"></div></div>' +
                '<div style="margin-top:16px;font-size:14px;color:#8b949e">完成后将自动重启</div></div></div>';
            document.body.insertAdjacentHTML('beforeend', progressHtml);
            
            // 模拟进度
            var progress = 0;
            var interval = setInterval(function() {
                progress += Math.random() * 15;
                if (progress > 90) progress = 90;
                document.getElementById('startupProgress').style.width = progress + '%';
            }, 200);
            
            // 3秒后重启
            setTimeout(function() {
                clearInterval(interval);
                document.getElementById('startupProgress').style.width = '100%';
                setTimeout(function() {
                    if (window.quickRestart) {
                        window.quickRestart();
                    } else {
                        location.reload();
                    }
                }, 500);
            }, 3000);
        }
        
        function refreshLocalhostInfo() {
            apiGet('/api/v1/localhost').then(function(result) {
                if (result.success && result.data) {
                    var info = result.data;
                    document.getElementById('localhost-hostname').textContent = info.hostname || '-';
                    document.getElementById('localhost-cpu').textContent = info.cpu_model || '-';
                    document.getElementById('localhost-ram').textContent = info.ram_gb ? info.ram_gb + ' GB' : '-';
                    var gpu = (info.gpu_names || []).join(', ') || '-';
                    if (info.vram_gb > 0) gpu += ' (' + info.vram_gb + 'GB)';
                    document.getElementById('localhost-gpu').textContent = gpu;
                    document.getElementById('localhost-ip').textContent = info.local_ip || '-';
                    document.getElementById('localhost-gateway').textContent = info.gateway || '-';
                    addLog('done', '本机信息已刷新');
                }
            }).catch(function(e) { addLog('error', '刷新失败: ' + e); });
        }
        // v6.0: 从后端恢复连接状态
        function restoreConnectionState() {
            // v7.12: 初始状态禁用所有控件
            if (window.disableAllControls) window.disableAllControls('请连接设备');

            apiGet('/api/v1/ptz/connected').then(function(r) {
                if (r && r.success && r.connected && r.device) {
                    // v7.12: 已连接状态
                    var device = r.device;
                    window.connectedDevice = device;
                    console.log('[v7.12] 已恢复连接:', device.ip);

                    // 启用所有控件
                    if (window.enableAllControls) window.enableAllControls();

                    // 更新状态显示
                    if (window.updateDeviceStatus) window.updateDeviceStatus(device);

                    // 加载图像参数
                    if (window.loadDeviceImageParams) {
                        setTimeout(function() { window.loadDeviceImageParams(device.ip); }, 300);
                    }

                    // WASM SDK: 恢复连接时同步登录
                    if (typeof onDeviceConnected === 'function') onDeviceConnected();

                } else if (r && r.success && !r.connected && r.device) {
                    // v7.12: 未连接但有上次设备 → 自动连接
                    console.log('[v7.12] 有上次连接设备，自动连接:', r.device.ip);
                    
                    // 更新状态显示
                    if (window.updateDeviceStatus) window.updateDeviceStatus(r.device);
                    
                    // 自动连接
                    if (window.connectDevice) {
                        window.connectDevice(r.device.ip);
                    }

                } else if (r && r.success && !r.connected && !r.device) {
                    // v7.12: 无上次连接设备
                    console.log('[v7.12] 无上次连接设备');
                    
                    // 更新状态显示
                    if (window.updateDeviceStatus) window.updateDeviceStatus(null);
                    
                    // 显示提示
                    setTimeout(function() {
                        showToast('info', '无上次连接设备,请执行发现流程');
                    }, 1000);
                }
            }).catch(function(e) {
                console.warn('[v7.12] 获取连接状态失败:', e);
                // 禁用所有控件
                if (window.disableAllControls) window.disableAllControls('请连接设备');
            });
        }
