    function toggleRecord() {
        if (!window._isRecording) {
            // 立即更新状态，防止重复点击
            updateRecordToggleUI(true);
            consoleRecordStart();
        } else {
            // v7.111: 立即重置UI状态，不等WASM回调
            updateRecordToggleUI(false);
            if (typeof updateMediaOutputStatus === 'function') updateMediaOutputStatus('idle');
            consoleRecordStop();
        }
    }

    // 录像状态更新（由 consoleRecordStart/Stop 调用）
    function updateRecordToggleUI(isRecording) {
        window._isRecording = isRecording;
        var btn = document.getElementById('btnConsoleRecord');
        if (btn) {
            btn.textContent = isRecording ? '⏹ 停止' : '⏺ 录像';
            btn.className = isRecording ? 'btn btn-danger btn-sm' : 'btn btn-warning btn-sm';
        }
    }

    // 媒体信息日志（输出到左侧 mediaLogBox）
