function uploadRecordedFile(expectedName) {
            var input = document.createElement('input');
            input.type = 'file';
            input.accept = 'video/mp4';
            input.onchange = function(e) {
                var file = e.target.files[0];
                if (!file) return;
                var formData = new FormData();
                formData.append('file', file, expectedName || file.name);
                fetch('/api/v1/files/upload-record', {method:'POST', body: formData})
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            showToast('success', '录像已上传: ' + data.filename);
                            if (typeof refreshFiles === 'function') refreshFiles();
                        } else {
                            showToast('error', '上传失败: ' + (data.message || '未知错误'));
                        }
                    })
                    .catch(function(err) { showToast('error', '上传异常: ' + err.message); });
            };
            input.click();
        }



        // ============== Live Stack 实时叠加 ==============
        var liveStackMode = 'off';
        var liveStackRunning = false;
        var liveStackFrameCount = 0;
        var liveStackTargetFrames = 0;
        var liveStackInterval = null;

