// WASM SDK 录制存到浏览器下载目录，服务端 shutil.move 到配置路径
function moveRecordedFile(filename, deviceIp) {
    if (!filename) return;
    showToast('info', '正在转移录像...');
    fetch('/api/v1/files/move-recording', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({filename: filename, device_ip: deviceIp || ''})
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
        if (data.success) {
            showToast('success', '录像已保存');
            if (typeof refreshFiles === 'function') refreshFiles();
        } else {
            showToast('error', '转移失败: ' + (data.message || '未知错误'));
        }
    })
    .catch(function(err) { showToast('error', '转移异常: ' + err.message); });
}

