"""
v7.113 E2E 测试：静默移动录像文件
策略：打开页面后直接用 JS 操作录制，验证文件从 Downloads 移动到配置路径
"""
import sys, io, os, json, time, traceback
from pathlib import Path
from datetime import datetime

sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')

BASE_URL = "http://127.0.0.1:10280"
ASTROHUB_DIR = Path(__file__).resolve().parent.parent

# 读取配置路径
DATA_DIR = ASTROHUB_DIR / "data"
storage = json.loads((DATA_DIR / "config" / "storage.json").read_text(encoding="utf-8"))
RECORD_PATH = storage.get("record_path", "")
print(f"配置存储路径: {RECORD_PATH}")

DOWNLOADS = Path.home() / "Downloads"
date_str = datetime.now().strftime("%Y-%m-%d")
src_dir = DOWNLOADS / date_str
dst_dir = Path(RECORD_PATH) / date_str

# 记录测试前文件
before_src = set(str(p) for p in src_dir.glob("*.mp4")) if src_dir.exists() else set()
before_dst = set(str(p) for p in dst_dir.glob("*.mp4")) if dst_dir.exists() else set()

results = []
passed = 0
failed = 0

def check(desc, condition, detail=""):
    global passed, failed
    if condition:
        passed += 1
        results.append(f"  PASS: {desc}")
    else:
        failed += 1
        results.append(f"  FAIL: {desc} -- {detail}")

from playwright.sync_api import sync_playwright

with sync_playwright() as p:
    browser = p.chromium.launch(
        headless=False,
        args=[
            '--disable-web-security',
            '--allow-running-insecure-content',
            '--unsafely-treat-insecure-origin-as-secure=http://127.0.0.1:10280',
        ]
    )
    context = browser.new_context(accept_downloads=False)
    page = context.new_page()

    # 监听弹窗（不应该出现）
    file_chooser_seen = [False]
    page.on("filechooser", lambda c: file_chooser_seen.__setitem__(0, True))

    try:
        # Step 1: 打开页面
        print("\n[1/5] 打开页面...")
        page.goto(BASE_URL, wait_until="domcontentloaded", timeout=15000)
        page.wait_for_timeout(3000)
        print("  页面已加载")

        # Step 2: 快速连接设备
        print("\n[2/5] 快速连接设备...")
        # 直接用 JS 触发快速连接
        result = page.evaluate("""async () => {
            // 获取设备列表
            const r = await fetch('/api/v1/devices/list');
            const data = await r.json();
            const devices = data.data || data.devices || {};
            const devList = Array.isArray(devices) ? devices : Object.values(devices);
            if (devList.length === 0) return {ok: false, msg: 'no devices'};

            // 设置 connectedDevice
            const dev = devList[0];
            window.connectedDevice = dev;

            // 如果 WasmPlayer 已初始化，直接播放
            if (typeof WasmPlayer !== 'undefined' && WasmPlayer.playing) {
                return {ok: true, msg: 'already playing', ip: dev.ip};
            }

            // 尝试通过 quickConnect 函数连接
            if (typeof quickConnect === 'function') {
                // 先确保开关打开
                var sw = document.getElementById('quickConnectSwitch');
                if (sw && !sw.checked) {
                    sw.checked = true;
                    quickConnect(true);
                }
                return {ok: true, msg: 'quickConnect called', ip: dev.ip};
            }
            return {ok: false, msg: 'no WasmPlayer or quickConnect'};
        }""")
        print(f"  连接结果: {result}")
        check("设备连接", result.get("ok"), str(result))

        # 等待播放建立
        page.wait_for_timeout(5000)

        # Step 3: 开始录像
        print("\n[3/5] 开始录像...")
        record_result = page.evaluate("""async () => {
            if (typeof consoleRecordStart !== 'function') return {ok: false, msg: 'consoleRecordStart not found'};
            if (!window.connectedDevice) return {ok: false, msg: 'no connectedDevice'};

            var dev = window.connectedDevice;
            var deviceName = (dev.name || dev.device_name || dev.ip || 'device').replace(/[^a-zA-Z0-9\\u4e00-\\u9fa5_-]/g, '_');
            var now = new Date();
            var dateStr = now.getFullYear() + String(now.getMonth()+1).padStart(2,'0') + String(now.getDate()).padStart(2,'0');
            var timeStr = String(now.getHours()).padStart(2,'0') + String(now.getMinutes()).padStart(2,'0') + String(now.getSeconds()).padStart(2,'0');
            if (!window._recordCounter) window._recordCounter = {};
            var dayKey = dateStr + '_' + deviceName;
            window._recordCounter[dayKey] = (window._recordCounter[dayKey] || 0) + 1;
            var seq = String(window._recordCounter[dayKey]).padStart(4, '0');
            var filename = deviceName + '_' + dateStr + '_' + timeStr + '_' + seq;
            window._currentRecordFile = filename + '.mp4';
            window._isRecording = true;

            return new Promise(function(resolve) {
                if (typeof wasmStartRecord !== 'function') {
                    resolve({ok: false, msg: 'wasmStartRecord not found'});
                    return;
                }
                wasmStartRecord(filename).then(function(r) {
                    resolve({ok: r && r.success, filename: filename, result: r});
                }).catch(function(e) {
                    resolve({ok: false, msg: e.message});
                });
            });
        }""")
        print(f"  录像结果: {record_result}")
        check("录像启动", record_result.get("ok"), str(record_result))
        recorded_filename = record_result.get("filename", "")

        # Step 4: 等几秒后停止录像
        print("\n[4/5] 停止录像...")
        page.wait_for_timeout(5000)
        stop_result = page.evaluate("""async () => {
            if (typeof wasmStopRecord !== 'function') return {ok: false, msg: 'wasmStopRecord not found'};
            var recordedFile = window._currentRecordFile;
            return new Promise(function(resolve) {
                wasmStopRecord().then(function(r) {
                    // 手动调用 moveRecordedFile
                    if (recordedFile && typeof moveRecordedFile === 'function') {
                        var ip = (window.connectedDevice && window.connectedDevice.ip) || '';
                        moveRecordedFile(recordedFile, ip);
                    }
                    window._isRecording = false;
                    resolve({ok: r && r.success, filename: recordedFile});
                }).catch(function(e) {
                    resolve({ok: false, msg: e.message});
                });
            });
        }""")
        print(f"  停止结果: {stop_result}")
        check("录像停止", stop_result.get("ok"), str(stop_result))

        # 等待 move-recording API 完成
        page.wait_for_timeout(3000)

        # 验证无弹窗
        check("无文件选择器弹窗", not file_chooser_seen[0])

        # Step 5: 验证文件移动
        print("\n[5/5] 验证文件移动...")
        new_src = set(str(p) for p in src_dir.glob("*.mp4")) if src_dir.exists() else set()
        new_dst = set(str(p) for p in dst_dir.glob("*.mp4")) if dst_dir.exists() else set()
        added_src = new_src - before_src
        added_dst = new_dst - before_dst
        print(f"  Downloads 新增: {added_src}")
        print(f"  存储路径新增: {added_dst}")

        file_moved = len(added_dst) > 0 and len(added_src) == 0
        check("文件已从Downloads移动到存储路径", file_moved,
              f"Downloads新增={added_src}, 存储新增={added_dst}")

        if added_dst:
            for f in added_dst:
                sz = Path(f).stat().st_size
                print(f"  已保存: {Path(f).name} ({sz} bytes)")

    except Exception as e:
        print(f"\n  测试异常: {e}")
        traceback.print_exc()
        results.append(f"  ERROR: {str(e)}")
    finally:
        browser.close()

# 汇总
print("\n" + "=" * 50)
print(f"E2E 测试结果: {passed} PASS / {failed} FAIL")
print("=" * 50)
for r in results:
    print(r)

sys.exit(1 if failed > 0 else 0)

