function onDeviceConnected() {
        if (!window.connectedDevice || !window.connectedDevice.ip) {
            console.log('[WASM] No device info, skip WASM login');
            return;
        }
        
        // 如果 SDK 已就绪，立即登录
        if (WasmPlayer && WasmPlayer.sdkReady) {
            var ip = window.connectedDevice.ip;
            var port = window.connectedDevice.port || 80;
            var username = window.connectedDevice.username || 'admin';
            var password = window.connectedDevice.password || '';
            
            wasmLogin(ip, port, username, password).then(function(result) {
                console.log('[WASM] Login result:', result);
                // v7.111: 登录后自动播放（如果在主控台页面）
                var activePage = document.querySelector('.page.active');
                if (activePage && activePage.id === 'page-console') {
                    var channel = WasmPlayer.channel || 1;
                    var streamType = window._currentStreamType || 3;
                    wasmStartRealPlay(channel, streamType, true);
                }
            }).catch(function(err) {
                console.error('[WASM] Login failed:', err);
            });
        }
        // 如果 SDK 未就绪，等待 wasm:ready 事件触发自动登录
    }

    // 设备断开后 - WASM 同步登出
    function onDeviceDisconnected() {
        if (typeof wasmStopRealPlay === 'function') wasmStopRealPlay();
        if (typeof wasmLogout === 'function') wasmLogout();
        // v7.111: 断开后重置码流按钮状态
        setTimeout(updateStreamButtons, 500);
    }

    // 主控台按钮接口 - 开始预览
    function doStartRealPlay() {
        var channel = WasmPlayer.channel || 1;
        var streamType = window._currentStreamType || 2;
        wasmStartRealPlay(channel, streamType, true);
    }

    // 主控台按钮接口 - 停止预览
    function doStopPreview() {
        wasmStopRealPlay();
        setTimeout(updateStreamButtons, 500);  // 等待状态更新
    }

    // 码流切换+预览（运动控制区码流按钮）
    window._currentStreamType = 3;  // 默认第三码流
    window._isRecording = false;

