import sys, io, os, re
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')

for root, dirs, files in os.walk('src/web'):
    for f in files:
        if not f.endswith('.html'):
            continue
        path = os.path.join(root, f)
        with open(path, 'r', encoding='utf-8', errors='ignore') as fh:
            c = fh.read()

        # Find all HTML elements that contain 'connect' and 'limit' in id
        pattern1 = re.compile(r'<[^>]*id="[^"]*[Cc]onnect[^"]*[Ll]imit[^"]*"[^>]*>')
        for m in pattern1.finditer(c):
            print(f'[{path}] {m.group()[:300]}')

        pattern2 = re.compile(r"<[^>]*id='[^']*[Cc]onnect[^']*[Ll]imit[^']*'[^>]*>")
        for m in pattern2.finditer(c):
            print(f'[{path}] {m.group()[:300]}')

        # Also look for onclick="connectLimitTestRun"
        onclick_pattern = re.compile(r'<[^>]*onclick="connectLimitTestRun[^"]*"[^>]*>')
        for m in onclick_pattern.finditer(c):
            print(f'[{path}] ONCLICK: {m.group()[:400]}')
        onclick_pattern2 = re.compile(r"<[^>]*onclick='connectLimitTestRun[^']*'[^>]*>")
        for m in onclick_pattern2.finditer(c):
            print(f'[{path}] ONCLICK: {m.group()[:400]}')

