// 限位检测(连接设备页面版)
function connectLimitTestRun() {
    var deviceIp = document.getElementById('advConnectDevice').value;
    if (!deviceIp) { showToast('warning', '请先选择设备'); return; }
    var device = allDevices.find(function(d) { return d.ip === deviceIp; });
    var btn = document.getElementById('btnConnectLimitRun');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner" style="display:inline-block"></span> 测试中...';
    document.getElementById('connectLimitProgress').style.display = 'block';
    document.getElementById('connectLimitResultMini').innerHTML = '';
    addLog('info', '限位检测开始: ' + deviceIp);
    apiPost('/api/v1/advanced/limit/run', {
        device_ip: deviceIp,
        username: (device && device.username) || 'admin',
        password: (device && device.password) || '',
        port: (device && device.port) || 80
    }).then(function(resp) {
        btn.disabled = false;
        btn.innerHTML = '▶ 开始检测';
        document.getElementById('connectLimitProgress').style.display = 'none';
        if (resp && resp.success) {
            showToast('success', '限位检测完成');
            addLog('success', '限位检测完成: ' + (resp.message || ''));
            renderConnectLimitResultMini(resp.results || {});
            renderConnectFullResults(resp.results || {}, 'limit');
        } else {
            showToast('error', resp ? resp.message : '测试失败');
            addLog('error', '限位检测失败: ' + (resp ? resp.message : '未知'));
            document.getElementById('connectLimitResultMini').innerHTML = '<span style="color:#f85149;font-size:12px">❌ ' + (resp ? resp.message : '测试失败') + '</span>';
        }
    }).catch(function(e) {
        btn.disabled = false;
        btn.innerHTML = '▶ 开始检测';
        document.getElementById('connectLimitProgress').style.display = 'none';
        showToast('error', '测试异常: ' + e.message);
    });
    // REMOVED simulateProgress for connectLimitTestRun
}
